
function deepClone(obj = {}) {
    if (typeof obj !== 'object' || obj == null) {
        return obj
    }

    let result
    if (obj instanceof Array) {
        result = []
    } else {
        result = {}
    }

    for (let key in obj) {
        // 保证 key 不是原型的属性
        if (obj.hasOwnProperty(key)) {
            // 递归调用！！！
            result[key] = deepClone(obj[key])
        }
    }
    // 返回结果
    return result
}
export const install = function (Vue) {
    Vue.directive('lock', {
        inserted(el, bind, vnode) {
            let lockFlag;
            let lockName = bind.value.lock;
            let unLockName = bind.value.unLock;
            let context = bind.value.getContext();
            var copy= deepClone(context);
            Object.defineProperties(context,{
                [lockName]:{
                    get(){
                        console.log("lock方法被调用");
                        if(lockFlag){
                            return ()=>{console.log("方法已锁定")};
                        }
                        lockFlag=true;
                        return copy.lock;
                    }
                },
                [unLockName]:{
                    get(){
                        console.log("unLock方法被调用");
                        lockFlag=false;
                        return copy.unLock;
                    }
                }
            })
        }
    });
};